import { useState } from "react";
import { useAuth } from "../../context/AuthContext";
import PassengerSidebar from "../../components/passenger/PassengerSidebar";
import PassengerTopbar from "../../components/passenger/PassengerTopbar";
import "../../styles/auth.css";
import "../../styles/global.css";

export default function PassengerProfilePage() {
  const { user, updateUser, logout } = useAuth();

  const initialName =
    `${user?.firstName || ""} ${user?.lastName || ""}`.trim() ||
    user?.fullNames ||
    "";

  const [form, setForm] = useState({
    fullName: initialName,
    email: user?.email || "",
    phone: user?.phone || "",
    emergencyName: user?.emergencyName || "",
    emergencyPhone: user?.emergencyPhone || "",
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleSave = (e) => {
    e.preventDefault();

    const [firstName, ...rest] = form.fullName.trim().split(" ");
    const lastName = rest.join(" ");

    updateUser?.({
      firstName: firstName || "",
      lastName: lastName || "",
      fullNames: form.fullName,
      email: form.email,
      phone: form.phone,
      emergencyName: form.emergencyName,
      emergencyPhone: form.emergencyPhone,
    });

    alert("Profile updated successfully!");
  };

  const handleSignOut = async () => {
    const ok = window.confirm("Are you sure you want to sign out?");
    if (!ok) return;
    await logout?.();
  };

  return (
    <div className="shell">
      <PassengerSidebar />
      <div className="main">
        <PassengerTopbar
          title="Passenger Profile"
          subtitle="Manage your account and safety information"
        />

        <div className="auth-page" style={{ padding: 0, minHeight: "auto" }}>
          <div className="auth-card" style={{ width: "100%", maxWidth: "100%" }}>
            <div className="auth-left">
              <div className="watermark">PS</div>
              <div className="brand-content">
                <h2>Passenger Profile Setup</h2>
                <p>
                  Keep your profile details up to date for smoother bookings,
                  emergency support, and account security.
                </p>
              </div>
              <div className="left-footer">
                <span>Secure</span>
                <span>Trusted</span>
                <span>Safe</span>
                <span>Ready</span>
              </div>
            </div>

            <div className="auth-right">
              <h1>My Profile</h1>
              <p className="subtitle">
                Update your personal and emergency contact information.
              </p>

              <form className="auth-form" onSubmit={handleSave}>
                <div className="field">
                  <label>Full Name</label>
                  <input
                    name="fullName"
                    type="text"
                    placeholder="Enter full name"
                    value={form.fullName}
                    onChange={handleChange}
                    required
                  />
                </div>

                <div className="field">
                  <label>Email Address</label>
                  <input
                    name="email"
                    type="email"
                    placeholder="Enter email"
                    value={form.email}
                    onChange={handleChange}
                    required
                  />
                </div>

                <div className="field">
                  <label>Phone Number</label>
                  <input
                    name="phone"
                    type="text"
                    placeholder="Enter phone number"
                    value={form.phone}
                    onChange={handleChange}
                  />
                </div>

                <div className="field">
                  <label>Emergency Contact Name</label>
                  <input
                    name="emergencyName"
                    type="text"
                    placeholder="Enter emergency contact name"
                    value={form.emergencyName}
                    onChange={handleChange}
                  />
                </div>

                <div className="field">
                  <label>Emergency Contact Number</label>
                  <input
                    name="emergencyPhone"
                    type="text"
                    placeholder="Enter emergency contact number"
                    value={form.emergencyPhone}
                    onChange={handleChange}
                  />
                </div>

                <div className="grid-2" style={{ marginTop: 8 }}>
                  <button className="btn-primary" type="submit">
                    Save Profile
                  </button>
                  <button
                    className="btn btn-danger"
                    type="button"
                    onClick={handleSignOut}
                  >
                    Sign Out
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
